package metric

import (
	"context"
	"fmt"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/docgraph"
	ddxexec "github.com/DocumentDrivenDX/ddx/internal/exec"
)

var errNotMetricArtifact = fmt.Errorf("not a metric artifact")

type Store struct {
	WorkingDir string
	execStore  *ddxexec.Store
}

func NewStore(workingDir string) *Store {
	return &Store{
		WorkingDir: workingDir,
		execStore:  ddxexec.NewStore(workingDir),
	}
}

// ListArtifacts returns all MET-* artifacts in document ID order.
func (s *Store) ListArtifacts() ([]docgraph.Document, error) {
	graph, err := docgraph.BuildGraph(s.WorkingDir)
	if err != nil {
		return nil, err
	}
	ids := graph.All()
	out := make([]docgraph.Document, 0, len(ids))
	for _, id := range ids {
		if !strings.HasPrefix(id, "MET-") {
			continue
		}
		doc, ok := graph.Show(id)
		if !ok {
			continue
		}
		out = append(out, doc)
	}
	return out, nil
}

func (s *Store) Validate(metricID string) (*Definition, *docgraph.Document, error) {
	doc, err := s.loadMetricArtifact(metricID)
	if err != nil {
		return nil, nil, err
	}
	def, err := s.LoadDefinition(metricID)
	if err != nil {
		return nil, nil, err
	}
	if def.MetricID != metricID {
		return nil, nil, fmt.Errorf("metric definition %q does not target %q", def.DefinitionID, metricID)
	}
	if len(def.Command) == 0 {
		return nil, nil, fmt.Errorf("metric definition %q has no command", def.DefinitionID)
	}
	if def.Comparison == "" {
		def.Comparison = ComparisonLowerIsBetter
	}
	switch def.Comparison {
	case ComparisonLowerIsBetter, ComparisonHigherIsBetter:
	default:
		return nil, nil, fmt.Errorf("metric definition %q has invalid comparison %q", def.DefinitionID, def.Comparison)
	}
	return &def, doc, nil
}

func (s *Store) Run(ctx context.Context, metricID string) (HistoryRecord, error) {
	def, _, err := s.Validate(metricID)
	if err != nil {
		return HistoryRecord{}, err
	}
	rec, err := s.execStore.Run(ctx, def.DefinitionID)
	if err != nil {
		return HistoryRecord{}, err
	}
	return metricHistoryFromExec(rec)
}

func (s *Store) Compare(metricID, against string) (HistoryRecord, ComparisonResult, error) {
	history, err := s.History(metricID)
	if err != nil {
		return HistoryRecord{}, ComparisonResult{}, err
	}
	if len(history) == 0 {
		return HistoryRecord{}, ComparisonResult{}, fmt.Errorf("no history for metric %q", metricID)
	}
	current := history[len(history)-1]
	target, err := selectComparisonTarget(history, against)
	if err != nil {
		return HistoryRecord{}, ComparisonResult{}, err
	}
	result := comparisonFor(current.Value, target.Value, current.Comparison.Direction)
	current.Comparison = result
	return current, result, nil
}

func (s *Store) Trend(metricID string) (TrendSummary, error) {
	history, err := s.History(metricID)
	if err != nil {
		return TrendSummary{}, err
	}
	if len(history) == 0 {
		return TrendSummary{}, fmt.Errorf("no history for metric %q", metricID)
	}
	summary := TrendSummary{MetricID: metricID, Min: history[0].Value, Max: history[0].Value, Latest: history[len(history)-1].Value, Unit: history[len(history)-1].Unit, UpdatedAt: history[len(history)-1].ObservedAt}
	var sum float64
	for _, rec := range history {
		if rec.Value < summary.Min {
			summary.Min = rec.Value
		}
		if rec.Value > summary.Max {
			summary.Max = rec.Value
		}
		sum += rec.Value
		summary.UpdatedAt = rec.ObservedAt
		if rec.Unit != "" {
			summary.Unit = rec.Unit
		}
	}
	summary.Count = len(history)
	summary.Average = sum / float64(len(history))
	return summary, nil
}

func (s *Store) LoadDefinition(metricID string) (Definition, error) {
	if s.execStore == nil {
		return Definition{}, fmt.Errorf("metric store is not initialized")
	}
	defs, err := s.execStore.ListDefinitions(metricID)
	if err != nil {
		return Definition{}, err
	}
	var (
		best  Definition
		found bool
	)
	for _, def := range defs {
		if def.ID == "" {
			continue
		}
		mapped, err := metricDefinitionFromExec(def)
		if err != nil {
			return Definition{}, err
		}
		if mapped.MetricID != metricID || !mapped.Active {
			continue
		}
		if !found || mapped.CreatedAt.After(best.CreatedAt) || (mapped.CreatedAt.Equal(best.CreatedAt) && mapped.DefinitionID > best.DefinitionID) {
			best = mapped
			found = true
		}
	}
	if !found {
		return Definition{}, fmt.Errorf("metric definition for %q not found", metricID)
	}
	if best.DefinitionID == "" {
		return Definition{}, fmt.Errorf("metric definition for %q is missing definition_id", metricID)
	}
	return best, nil
}

func (s *Store) History(metricID string) ([]HistoryRecord, error) {
	if s.execStore == nil {
		return []HistoryRecord{}, fmt.Errorf("metric store is not initialized")
	}
	records, err := s.execStore.History(metricID, "")
	if err != nil {
		return nil, err
	}
	out := make([]HistoryRecord, 0, len(records))
	for _, rec := range records {
		mapped, err := metricHistoryFromExec(rec)
		if err != nil {
			return nil, err
		}
		if mapped.MetricID == metricID {
			out = append(out, mapped)
		}
	}
	return out, nil
}

func (s *Store) loadMetricArtifact(metricID string) (*docgraph.Document, error) {
	if !strings.HasPrefix(metricID, "MET-") {
		return nil, fmt.Errorf("%w: %s", errNotMetricArtifact, metricID)
	}
	graph, err := docgraph.BuildGraph(s.WorkingDir)
	if err != nil {
		return nil, err
	}
	doc, ok := graph.Show(metricID)
	if !ok {
		return nil, fmt.Errorf("metric artifact %q not found", metricID)
	}
	return &doc, nil
}

func selectComparisonTarget(history []HistoryRecord, against string) (HistoryRecord, error) {
	switch against {
	case "", "latest":
		return history[len(history)-1], nil
	case "baseline":
		return history[0], nil
	default:
		for _, rec := range history {
			if rec.RunID == against {
				return rec, nil
			}
		}
		return HistoryRecord{}, fmt.Errorf("comparison target %q not found", against)
	}
}

func comparisonFor(current, baseline float64, direction string) ComparisonResult {
	delta := current - baseline
	if direction == ComparisonHigherIsBetter {
		delta = baseline - current
	}
	return ComparisonResult{
		Baseline:  baseline,
		Delta:     delta,
		Direction: direction,
	}
}

package metric

import ddxexec "github.com/DocumentDrivenDX/ddx/internal/exec"

func metricDefinitionFromExec(def ddxexec.Definition) (Definition, error) {
	out := Definition{
		DefinitionID: def.ID,
		MetricID:     metricArtifactID(def.ArtifactIDs),
		Command:      append([]string{}, def.Executor.Command...),
		Cwd:          def.Executor.Cwd,
		Env:          cloneStringMap(def.Executor.Env),
		Thresholds: Thresholds{
			Warn:    def.Evaluation.Thresholds.WarnMS,
			Ratchet: def.Evaluation.Thresholds.RatchetMS,
			Unit:    "",
		},
		Comparison: def.Evaluation.Comparison,
		Active:     def.Active,
		CreatedAt:  def.CreatedAt,
	}
	if def.Result.Metric != nil {
		out.Thresholds.Unit = def.Result.Metric.Unit
	}
	return out, nil
}

func metricHistoryFromExec(rec ddxexec.RunRecord) (HistoryRecord, error) {
	out := HistoryRecord{
		RunID:        rec.RunID,
		MetricID:     metricArtifactID(rec.ArtifactIDs),
		DefinitionID: rec.DefinitionID,
		ObservedAt:   rec.StartedAt,
		Status:       StatusPass,
		ExitCode:     rec.ExitCode,
		DurationMS:   rec.FinishedAt.Sub(rec.StartedAt).Milliseconds(),
		Stdout:       rec.Result.Stdout,
		Stderr:       rec.Result.Stderr,
		ArtifactID:   metricArtifactID(rec.ArtifactIDs),
	}
	if rec.Status != ddxexec.StatusSuccess {
		out.Status = StatusFail
	}
	if rec.Result.Metric != nil {
		out.Value = rec.Result.Metric.Value
		out.Unit = rec.Result.Metric.Unit
		out.Comparison = ComparisonResult{
			Baseline:  rec.Result.Metric.Comparison.Baseline,
			Delta:     rec.Result.Metric.Comparison.Delta,
			Direction: rec.Result.Metric.Comparison.Direction,
		}
	}
	return out, nil
}

func cloneStringMap(in map[string]string) map[string]string {
	if len(in) == 0 {
		return nil
	}
	out := make(map[string]string, len(in))
	for k, v := range in {
		out[k] = v
	}
	return out
}

func metricArtifactID(ids []string) string {
	if len(ids) == 0 {
		return ""
	}
	for _, id := range ids {
		if len(id) >= 4 && id[:4] == "MET-" {
			return id
		}
	}
	return ids[0]
}

// Package metric defines the domain types and store for metric artifact
// observation. HistoryRecord, TrendSummary, ComparisonResult, Definition, and
// Thresholds are used by store.go and exec_bridge.go within this package and
// exported for use by cmd/metric.go. They are NOT projection-only types
// and cannot be inlined into cmd without creating a circular import.
package metric

import "time"

const (
	ComparisonLowerIsBetter  = "lower-is-better"
	ComparisonHigherIsBetter = "higher-is-better"
	StatusPass               = "pass"
	StatusFail               = "fail"
)

// Definition describes an executable metric runtime record.
type Definition struct {
	DefinitionID string            `json:"definition_id"`
	MetricID     string            `json:"metric_id"`
	Command      []string          `json:"command"`
	Cwd          string            `json:"cwd,omitempty"`
	Env          map[string]string `json:"env,omitempty"`
	Thresholds   Thresholds        `json:"thresholds,omitempty"`
	Comparison   string            `json:"comparison,omitempty"`
	Active       bool              `json:"active"`
	CreatedAt    time.Time         `json:"created_at"`
}

// Thresholds describe the target values used for pass/fail evaluation.
type Thresholds struct {
	Warn    float64 `json:"warn,omitempty"`
	Ratchet float64 `json:"ratchet,omitempty"`
	Unit    string  `json:"unit,omitempty"`
}

// HistoryRecord stores one metric observation.
type HistoryRecord struct {
	RunID        string           `json:"run_id"`
	MetricID     string           `json:"metric_id"`
	DefinitionID string           `json:"definition_id"`
	ObservedAt   time.Time        `json:"observed_at"`
	Status       string           `json:"status"`
	Value        float64          `json:"value"`
	Unit         string           `json:"unit,omitempty"`
	Comparison   ComparisonResult `json:"comparison"`
	ExitCode     int              `json:"exit_code"`
	DurationMS   int64            `json:"duration_ms,omitempty"`
	Stdout       string           `json:"stdout,omitempty"`
	Stderr       string           `json:"stderr,omitempty"`
	ArtifactID   string           `json:"artifact_id,omitempty"`
}

// ComparisonResult records the comparison against a baseline or target.
type ComparisonResult struct {
	Baseline  float64 `json:"baseline"`
	Delta     float64 `json:"delta"`
	Direction string  `json:"direction"`
}

// TrendSummary aggregates a sequence of history records.
type TrendSummary struct {
	MetricID  string    `json:"metric_id"`
	Count     int       `json:"count"`
	Min       float64   `json:"min"`
	Max       float64   `json:"max"`
	Average   float64   `json:"average"`
	Latest    float64   `json:"latest"`
	Unit      string    `json:"unit,omitempty"`
	UpdatedAt time.Time `json:"updated_at"`
}

package cmd

import (
	"encoding/json"
	"fmt"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/metric"
	"github.com/spf13/cobra"
)

func (f *CommandFactory) newMetricCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "metric",
		Short: "Inspect and run metric artifacts",
		Long:  "Manage DDx metric artifacts, run definitions, and observation history through ddx exec.",
		Run: func(cmd *cobra.Command, args []string) {
			_ = cmd.Help()
		},
	}

	cmd.AddCommand(f.newMetricValidateCommand())
	cmd.AddCommand(f.newMetricListCommand())
	cmd.AddCommand(f.newMetricShowCommand())
	cmd.AddCommand(f.newMetricRunCommand())
	cmd.AddCommand(f.newMetricCompareCommand())
	cmd.AddCommand(f.newMetricHistoryCommand())
	cmd.AddCommand(f.newMetricTrendCommand())

	return cmd
}

func (f *CommandFactory) metricStore() *metric.Store {
	return metric.NewStore(f.WorkingDir)
}

func (f *CommandFactory) metricHistory(metricID string) ([]metric.HistoryRecord, error) {
	return f.metricStore().History(metricID)
}

func (f *CommandFactory) newMetricValidateCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "validate <metric-id>",
		Short: "Validate a metric artifact and runtime definition",
		Args:  cobra.ExactArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			def, _, err := f.metricStore().Validate(args[0])
			if err != nil {
				return err
			}
			if cmd.Flags().Changed("json") {
				enc := json.NewEncoder(cmd.OutOrStdout())
				enc.SetIndent("", "  ")
				return enc.Encode(map[string]any{
					"metric_id":     args[0],
					"definition_id": def.DefinitionID,
					"status":        "ok",
				})
			}
			fmt.Fprintf(cmd.OutOrStdout(), "%s validated with %s\n", args[0], def.DefinitionID)
			return nil
		},
	}
	cmd.Flags().Bool("json", false, "Output JSON")
	return cmd
}

func (f *CommandFactory) newMetricListCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "list",
		Short: "List metric artifacts",
		RunE: func(cmd *cobra.Command, args []string) error {
			docs, err := f.metricStore().ListArtifacts()
			if err != nil {
				return err
			}
			if cmd.Flags().Changed("json") {
				enc := json.NewEncoder(cmd.OutOrStdout())
				enc.SetIndent("", "  ")
				return enc.Encode(docs)
			}
			for _, doc := range docs {
				if doc.Title != "" {
					fmt.Fprintf(cmd.OutOrStdout(), "%s  %s\n", doc.ID, doc.Title)
					continue
				}
				fmt.Fprintln(cmd.OutOrStdout(), doc.ID)
			}
			return nil
		},
	}
	cmd.Flags().Bool("json", false, "Output JSON")
	return cmd
}

func (f *CommandFactory) newMetricShowCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "show <metric-id>",
		Short: "Show one metric artifact and recent history",
		Args:  cobra.ExactArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			def, doc, err := f.metricStore().Validate(args[0])
			if err != nil {
				return err
			}
			history, err := f.metricHistory(args[0])
			if err != nil {
				return err
			}
			recent := history
			if len(recent) > 5 {
				recent = recent[len(recent)-5:]
			}
			if cmd.Flags().Changed("json") {
				enc := json.NewEncoder(cmd.OutOrStdout())
				enc.SetIndent("", "  ")
				return enc.Encode(map[string]any{
					"artifact":       doc,
					"definition":     def,
					"recent_history": recent,
				})
			}
			fmt.Fprintf(cmd.OutOrStdout(), "ID:        %s\n", doc.ID)
			if doc.Title != "" {
				fmt.Fprintf(cmd.OutOrStdout(), "Title:     %s\n", doc.Title)
			}
			fmt.Fprintf(cmd.OutOrStdout(), "Path:      %s\n", doc.Path)
			fmt.Fprintf(cmd.OutOrStdout(), "Definition: %s\n", def.DefinitionID)
			fmt.Fprintf(cmd.OutOrStdout(), "Command:   %s\n", joinCommand(def.Command))
			fmt.Fprintf(cmd.OutOrStdout(), "Created:   %s\n", def.CreatedAt.Format(time.RFC3339))
			fmt.Fprintln(cmd.OutOrStdout(), "Recent history:")
			if len(recent) == 0 {
				fmt.Fprintln(cmd.OutOrStdout(), "  (none)")
				return nil
			}
			for _, rec := range recent {
				fmt.Fprintf(cmd.OutOrStdout(), "  %s  %s  %.3f%s  %s\n", rec.ObservedAt.Format(time.RFC3339), rec.RunID, rec.Value, rec.Unit, rec.Status)
			}
			return nil
		},
	}
	cmd.Flags().Bool("json", false, "Output JSON")
	return cmd
}

func (f *CommandFactory) newMetricRunCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "run <metric-id>",
		Short: "Execute a metric definition",
		Args:  cobra.ExactArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			rec, err := f.metricStore().Run(cmd.Context(), args[0])
			if err != nil {
				return err
			}
			if cmd.Flags().Changed("json") {
				enc := json.NewEncoder(cmd.OutOrStdout())
				enc.SetIndent("", "  ")
				return enc.Encode(rec)
			}
			fmt.Fprintf(cmd.OutOrStdout(), "%s  %s  %.3f%s  %s\n", rec.ObservedAt.Format(time.RFC3339), rec.Status, rec.Value, rec.Unit, rec.RunID)
			return nil
		},
	}
	cmd.Flags().Bool("json", false, "Output JSON")
	return cmd
}

func (f *CommandFactory) newMetricCompareCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "compare <metric-id>",
		Short: "Compare the latest metric run to a target",
		Args:  cobra.ExactArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			against, _ := cmd.Flags().GetString("against")
			rec, result, err := f.metricStore().Compare(args[0], against)
			if err != nil {
				return err
			}
			if cmd.Flags().Changed("json") {
				enc := json.NewEncoder(cmd.OutOrStdout())
				enc.SetIndent("", "  ")
				return enc.Encode(map[string]any{
					"record":     rec,
					"comparison": result,
				})
			}
			fmt.Fprintf(cmd.OutOrStdout(), "%s  baseline=%.3f  delta=%.3f  %s\n", rec.RunID, result.Baseline, result.Delta, result.Direction)
			return nil
		},
	}
	cmd.Flags().String("against", "latest", "Compare against baseline, latest, or a run ID")
	cmd.Flags().Bool("json", false, "Output JSON")
	return cmd
}

